index.styles:
* { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'Hiragino Kaku Gothic ProN', 'Hiragino Sans', Meiryo, sans-serif; color: #333; line-height: 1.8; background: #feffff; }
    .hero { background: #333; color: #feffff; padding: 88px 20px 72px; text-align: center; position: relative; overflow: hidden; }
    .hero::before { content: ''; position: absolute; inset: 0; background: linear-gradient(135deg, rgba(21,183,136,0.25) 0%, transparent 55%, rgba(19,149,186,0.1) 100%); }
    .hero-inner { position: relative; max-width: 720px; margin: 0 auto; }
    .hero-icon { width: 120px; height: 120px; border-radius: 28px; box-shadow: 0 8px 32px rgba(21,183,136,0.35); margin-bottom: 1.25rem; }
    .hero .eyebrow { display: inline-block; background: rgba(255,255,255,0.1); border: 1px solid rgba(255,255,255,0.2); border-radius: 100px; padding: 6px 18px; font-size: 0.8rem; margin-bottom: 1rem; color: #6B7A96; }
    .hero h1 { font-size: 2.6rem; font-weight: 800; margin-bottom: 0.25rem; }
    .hero h1 small { display: block; font-size: 1.15rem; font-weight: 500; color: #6B7A96; margin-top: 0.35rem; }
    .hero .desc { font-size: 1rem; max-width: 580px; margin: 1.25rem auto 0; opacity: 0.92; }
    .badge-row { display: flex; flex-wrap: wrap; justify-content: center; gap: 10px; margin-top: 1.75rem; }
    .badge { background: rgba(255,255,255,0.12); border: 1px solid rgba(21,183,136,0.4); border-radius: 8px; padding: 8px 14px; font-size: 0.82rem; font-weight: 600; color: #F4F0E6; }
    section { padding: 72px 20px; }
    section:nth-child(even) { background: #f8faf9; }
    .container { max-width: 960px; margin: 0 auto; }
    .section-title { font-size: 1.55rem; font-weight: 700; text-align: center; margin-bottom: 0.5rem; }
    .section-subtitle { text-align: center; color: #666; font-size: 0.95rem; margin-bottom: 2.5rem; }
    .pain-list { display: grid; gap: 16px; margin-bottom: 2rem; }
    .pain-item { background: #fff; border-radius: 12px; padding: 20px 24px; border-left: 4px solid #ccc; box-shadow: 0 1px 4px rgba(0,0,0,0.04); }
    .pain-item strong { display: block; color: #333; margin-bottom: 4px; font-size: 0.95rem; }
    .pain-item span { font-size: 0.9rem; color: #666; }
    .compare-hero { display: flex; justify-content: center; gap: 16px; margin-top: 2rem; flex-wrap: wrap; align-items: stretch; }
    .compare-box { flex: 1; min-width: 200px; max-width: 280px; border-radius: 14px; padding: 24px 20px; text-align: center; }
    .compare-box.before { background: #fff; border: 1px dashed #ccc; }
    .compare-box.after { background: #f4f5f8; border: 2px solid #6B7A96; }
    .compare-box .label { font-size: 0.72rem; letter-spacing: 0.06em; color: #888; margin-bottom: 10px; font-weight: 600; }
    .compare-box .emoji { font-size: 2rem; margin-bottom: 8px; }
    .compare-box .text { font-size: 0.9rem; font-weight: 600; line-height: 1.55; color: #333; }
    .compare-arrow { display: flex; align-items: center; font-size: 1.5rem; color: #6B7A96; font-weight: 700; }
    .solution-banner { background: linear-gradient(135deg, #f4f5f8 0%, #e8f4f8 100%); border-radius: 16px; padding: 28px 32px; text-align: center; border: 1px solid rgba(21,183,136,0.25); margin-top: 2rem; }
    .solution-banner p { font-size: 1.1rem; color: #333; font-weight: 700; }
    .features-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 18px; }
    .feature-card { background: #fff; border-radius: 14px; padding: 24px; border: 1px solid #e4e7ef; box-shadow: 0 1px 4px rgba(0,0,0,0.04); }
    .feature-card .icon { font-size: 1.8rem; margin-bottom: 0.6rem; }
    .feature-card h3 { font-size: 1rem; margin-bottom: 0.4rem; color: #6B7A96; }
    .feature-card p { font-size: 0.88rem; color: #555; }
    .phase-list { display: grid; grid-template-columns: repeat(auto-fit, minmax(140px, 1fr)); gap: 12px; }
    .phase-pill { background: #fff; border: 2px solid #c5cad8; border-radius: 12px; padding: 16px 12px; text-align: center; font-weight: 700; font-size: 0.85rem; color: #6B7A96; }
    .phase-pill small { display: block; font-weight: 500; font-size: 0.75rem; color: #666; margin-top: 4px; }
    .pricing-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 20px; max-width: 640px; margin: 0 auto; }
    .pricing-card { background: #fff; border-radius: 14px; padding: 28px; border: 1px solid #e4e7ef; text-align: center; }
    .pricing-card.featured { border: 2px solid #6B7A96; box-shadow: 0 4px 20px rgba(21,183,136,0.12); }
    .pricing-card h3 { font-size: 1.1rem; margin-bottom: 0.5rem; color: #333; }
    .pricing-card .price { font-size: 1.4rem; font-weight: 800; color: #6B7A96; margin: 0.5rem 0 1rem; }
    .pricing-card ul { list-style: none; text-align: left; font-size: 0.88rem; color: #555; }
    .pricing-card li { padding: 6px 0; border-bottom: 1px solid #f0f0f0; }
    .pricing-card li:last-child { border-bottom: none; }
    .cta-section { text-align: center; }
    .cta-section .btn { display: inline-block; background: #6B7A96; color: #fff; text-decoration: none; padding: 14px 28px; border-radius: 10px; font-weight: 700; margin: 6px; }
    .cta-section .btn.secondary { background: #333; }
    .cta-section .micro { margin-top: 1rem; font-size: 0.82rem; color: #888; }
    .cta-section .store-badges { display: flex; justify-content: center; gap: 16px; margin-top: 1.5rem; flex-wrap: wrap; }
    .cta-section .store-badge { display: inline-block; background: #333; color: #fff; padding: 12px 24px; border-radius: 8px; font-size: 0.9rem; font-weight: 600; text-decoration: none; }
    .cta-section .store-badge.disabled { background: #999; cursor: default; opacity: 0.85; }
    .screenshot-gallery { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 20px; margin-top: 2rem; }
    .screenshot-item { border-radius: 12px; overflow: hidden; box-shadow: 0 2px 12px rgba(0,0,0,0.08); transition: transform 0.2s, box-shadow 0.2s; background: #fff; }
    .screenshot-item:hover { transform: translateY(-3px); box-shadow: 0 6px 24px rgba(0,0,0,0.12); }
    .screenshot-item img { width: 100%; height: auto; display: block; }
    .screenshot-label { display: block; padding: 10px; font-size: 0.85rem; font-weight: 600; color: #6B7A96; text-align: center; background: #fff; }
    footer { text-align: center; padding: 32px 20px; border-top: 1px solid #eee; font-size: 0.85rem; color: #888; }
    footer a { color: #6B7A96; text-decoration: none; }
    footer .links a { margin: 0 12px; }
    @media (max-width: 640px) {
      .hero h1 { font-size: 2rem; }
      .compare-arrow { width: 100%; justify-content: center; transform: rotate(90deg); margin: -8px 0; }
      .compare-box { max-width: 100%; }
    }

